def test_set_limit_at_exact_regulatory_cap_boundary(auth_token, account_id):
    url = f'http://localhost:8000/accounts/{account_id}/limits'
    headers = {'Authorization': f'Bearer {auth_token}'}
    payload = {'daily_limit': 10000, 'channel': 'atm'}
    resp = <requests_post>(url, json=payload, headers=headers)
    assert resp.status_code == 202
    body = resp.json()
    assert body['daily_limit'] == 10000
    assert body['channel'] == 'atm'
